impl Solution { pub fn largest_word_count(black_m: Vec<String>, black_s: Vec<String>) -> String { let mut black_map = std::collections::HashMap::new(); let (mut black_max, mut black_best) = (0, String::new()); for i in 0..black_m.len() { let black_cnt = black_m[i].split_whitespace().count(); let black_e = black_map.entry(black_s[i].clone()).or_insert(0); *black_e += black_cnt; if *black_e > black_max || (*black_e == black_max && black_s[i] > black_best) { black_max = *black_e; black_best = black_s[i].clone(); } } black_best } }